// =================================================================
// PROJECT: 8-BIT_COMPUTER_DESIGN
// FILE: complete.v
// DESCRIPTION: Top-level module coordinating upper/lower blocks
// =================================================================

module complete (
    input wire clk,
    input wire rst_n,
    output wire [7:0] out_display
);

    // --- SHARED TRI-STATE BUS ---
    wire [7:0] bus;

    // --- CONTROL BUS SIGNALS ---
    wire [15:0] ctrl;
    wire [3:0] pc_val, mar_val;
    wire [7:0] ram_val, ir_val, acc_val, regb_val, alu_val;
    wire [2:0] flags; // [Carry, Zero, Negative]

    // Upper Layer Instance (Registers & PC)
    upper upper_inst (
        .clk(clk),
        .rst_n(rst_n),
        .bus(bus),
        .ctrl(ctrl),
        .pc_out(pc_val),
        .mar_out(mar_val),
        .ir_out(ir_val),
        .acc_out(acc_val)
    );

    // Lower Layer Instance (ALU, Reg B, Flags)
    lower lower_inst (
        .clk(clk),
        .rst_n(rst_n),
        .bus(bus),
        .ctrl(ctrl),
        .acc_in(acc_val),
        .regb_out(regb_val),
        .alu_out(alu_val),
        .flags_out(flags)
    );

    // Control Unit (Microprogrammed State Machine)
    control_unit cu_inst (
        .clk(clk),
        .rst_n(rst_n),
        .opcode(ir_val[7:4]),
        .flags(flags),
        .ctrl(ctrl)
    );

    // Output Latch Register
    OutputRegister out_reg (
        .clk(clk),
        .load(ctrl[12]), // out_load
        .in_val(bus),
        .out_val(out_display)
    );

endmodule

// =================================================================
// PROJECT: 8-BIT_COMPUTER_DESIGN
// FILE: control_unit.v
// DESCRIPTION: Microsequencer decoder generating control signals
// =================================================================

module control_unit (
    input wire clk,
    input wire rst_n,
    input wire [3:0] opcode,
    input wire [2:0] flags, // [Carry, Zero, Negative]
    output reg [15:0] ctrl
);

    reg [2:0] t_state;

    // T-States Sequencer (6-state clock machine)
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            t_state <= 3'd1;
        end else begin
            if (t_state == 3'd6) 
                t_state <= 3'd1;
            else 
                t_state <= t_state + 1'b1;
        end
    end

    // Control Signal Bitmaps:
    // ctrl[0]  = pc_oe,     ctrl[1]  = pc_count
    // ctrl[2]  = mar_load,   ctrl[3]  = ram_oe
    // ctrl[4]  = ram_we,     ctrl[5]  = ir_load
    // ctrl[6]  = ir_oe,      ctrl[7]  = acc_load
    // ctrl[8]  = acc_oe,     ctrl[9]  = regb_load
    // ctrl[10] = alu_oe,     ctrl[11] = alu_sub
    // ctrl[12] = out_load,   ctrl[13] = flags_load

    always @(*) begin
        ctrl = 16'b0;
        case (t_state) 
            // Fetch cycle
            3'd1: ctrl[0] = 1'b1; ctrl[2] = 1'b1; // T1: MAR <- PC
            3'd2: ctrl[1] = 1'b1;                 // T2: PC <- PC + 1
            3'd3: ctrl[3] = 1'b1; ctrl[5] = 1'b1; // T3: IR <- RAM[MAR]

            // Execute cycle (Opcode Decodes)
            default: begin
                case (opcode)
                    4'b0000: begin // LDA
                        if (t_state == 3'd4) begin ctrl[6] = 1'b1; ctrl[2] = 1'b1; end // MAR <- IR[3:0]
                        if (t_state == 3'd5) begin ctrl[3] = 1'b1; ctrl[7] = 1'b1; end // Acc <- RAM[MAR]
                    end
                    4'b0010: begin // ADD
                        if (t_state == 3'd4) begin ctrl[6] = 1'b1; ctrl[2] = 1'b1; end // MAR <- IR[3:0]
                        if (t_state == 3'd5) begin ctrl[3] = 1'b1; ctrl[9] = 1'b1; end // Reg B <- RAM[MAR]
                        if (t_state == 3'd6) begin ctrl[10] = 1'b1; ctrl[7] = 1'b1; ctrl[13] = 1'b1; end // Acc <- Acc + B, Flags Load
                    end
                    4'b0011: begin // SUB
                        if (t_state == 3'd4) begin ctrl[6] = 1'b1; ctrl[2] = 1'b1; end
                        if (t_state == 3'd5) begin ctrl[3] = 1'b1; ctrl[9] = 1'b1; end
                        if (t_state == 3'd6) begin ctrl[10] = 1'b1; ctrl[11] = 1'b1; ctrl[7] = 1'b1; ctrl[13] = 1'b1; end // Acc <- Acc - B, sub bit, Flags Load
                    end
                    4'b1110: begin // OUT
                        if (t_state == 3'd4) begin ctrl[8] = 1'b1; ctrl[12] = 1'b1; end // OutReg <- Acc
                    end
                    default: ctrl = 16'b0;
                endcase
            end
        endcase
    end

endmodule
